using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLineNumber()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExactFormat()
    {
        var result = _formatter.FormatPhoneNumber("8005550199");

        Assert.AreEqual("(800) 555-0199", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsExactFormat()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.AreEqual("Dear Dr. Jones,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        StringAssert.Matches(result, new(@"^[a-z0-9-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  --Hello!  ");

        StringAssert.DoesNotMatch(result, new(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello!!!");

        StringAssert.DoesNotMatch(result, new(@"-$"));
    }

    [TestMethod]
    public void GenerateSlug_MixedCaseWithSpaces_StartsCorrectly()
    {
        var result = _formatter.GenerateSlug("My First Blog Post");

        StringAssert.StartsWith(result, "my-");
    }

    [TestMethod]
    public void GenerateSlug_MixedCaseWithSpaces_EndsCorrectly()
    {
        var result = _formatter.GenerateSlug("My First Blog Post");

        StringAssert.EndsWith(result, "-post");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidInput_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWith2Decimals()
    {
        var result = _formatter.FormatCurrency(5m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(10.50m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        StringAssert.Matches(result, new(@"^\$\d+\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_ReturnsExactFormat()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.AreEqual("$42.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-9.99m);

        StringAssert.Contains(result, "-");
    }
}

